mapper.select:
select wallet_id, user_id, balance, total_recharge, total_gift, total_consumed, frozen_amount, create_time, update_time
from t_wallet
where user_id = #{userId}

mapper.update:
update t_wallet
balance = #{balance}, total_recharge = #{totalRecharge}, total_gift = #{totalGift}, total_consumed = #{totalConsumed}, frozen_amount = #{frozenAmount}, update_time = now(),
where user_id = #{userId}

mapper.select:
select record_id, user_id, recharge_no, pay_amount, gift_amount, total_amount, template_id, pay_type, status, transaction_id, create_time, pay_time
from t_recharge_record
where recharge_no = #{rechargeNo}

mapper.update:
update t_recharge_record
status = #{status}, transaction_id = #{transactionId}, pay_time = #{payTime},
where record_id = #{recordId}

update t_recharge_record
set status = 1,
    pay_time = #{payTime}
where record_id = #{recordId}
  and status = 0

mapper.select:
select template_id, pay_amount, gift_amount, total_amount, sort_order, status, create_time
from t_recharge_template
where template_id = #{templateId}

mapper.update:
update t_recharge_template
pay_amount = #{payAmount}, gift_amount = #{giftAmount}, total_amount = #{totalAmount}, sort_order = #{sortOrder}, status = #{status},
where template_id = #{templateId}
